import type { RosterPlayer } from '../types/player.ts'

// ── NFL team skeleton ───────────────────────────────────────────────────────────
//
// All 32 teams, ready for you to fill in each roster by hand. The identities (name,
// abbreviation, conference, division) are done; the roster arrays start empty — populate them
// with RosterPlayer entries. The Buffalo Bills below are filled in as a complete template.
//
// Roster composition:
//   offense (skill, selectable): 4 WR, 3 TE, 2 RB
//   oline   (auto-placed):       5 OL
//   defense (selectable):        4 CB, 3 S, 4 LB
//   dline   (auto-placed):       4 DL
//   qb      (auto-placed):       1 QB
//
// A RosterPlayer looks like this (see types/player.ts for every rating field):
//   { id: 'kc_wr1', name: 'Player Name', position: 'WR', ovr: 88,
//     ratings: { speed: 90, catching: 85, routeRunning: 82 } }
// `ovr` is the cosmetic overall shown on the player card (no gameplay effect).
//
// Keep `id` globally unique — the convention is `<abbr lowercased>_<pos><n>`, e.g.
// 'kc_wr1', 'kc_ol3', 'sf_dl2'. Per-position rating fields are in types/player.ts:
//   WR/TE/RB → speed, catching, routeRunning/blocking/vision   QB → accuracy, speed, awareness
//   OL → strength, (blocking)   DL → strength, passRush         CB/S/LB → speed, awareness, strength
//
// The team OVRs (ovr / offOvr / defOvr) are cosmetic too — shown on the team card.

export type Conference = 'AFC' | 'NFC'
export type Division   = 'East' | 'North' | 'South' | 'West'

export interface NflTeam {
  id:         string        // stable key, e.g. 'KC'
  name:       string        // full name, e.g. 'Kansas City Chiefs'
  abbr:       string        // short code, e.g. 'KC'
  conference: Conference
  division:   Division
  phrase?:    string        // the team's signature rallying cry, e.g. 'Bills Mafia!'
  // Cosmetic overall ratings shown on the team card (no gameplay effect).
  ovr?:       number        // overall
  offOvr?:    number        // offense overall
  defOvr?:    number        // defense overall
  // Rosters.
  offense:    RosterPlayer[]   // skill pool: 4 WR, 3 TE, 2 RB
  defense:    RosterPlayer[]   // coverage pool: 4 CB, 3 S, 4 LB
  qb?:        RosterPlayer      // the quarterback (auto-placed)
  oline?:     RosterPlayer[]    // 5 OL (auto-placed) — now per-team so their ratings are dynamic
  dline?:     RosterPlayer[]    // 4 DL (auto-placed) — per-team ratings
}

